// Function to validate a cherry-picked commit hash
function validateCommitHash(hash) {
  // Check if the hash is a string
  if (typeof hash !== 'string') {
    return false;
  }
  // Check if the hash is 40 characters long
  if (hash.length !== 40) {
    return false;
  }
  // Check if the hash contains any non-hexadecimal characters
  for (let i = 0; i < hash.length; i++) {
    if ((hash[i] < '0' || hash[i] > '9') &&
        (hash[i] < 'a' || hash[i] > 'f') &&
        (hash[i] < 'A' || hash[i] > 'F')) {
      return false;
    }
  }
  return true;
}

