class Solution:
  def validateCommitHash(self, hash: str) -> bool:
    # Check if the hash is a string
    if not isinstance(hash, str):
      return False
    # Check if the hash is 40 characters long
    if len(hash) != 40:
      return False
    # Use a regular expression to match the hexadecimal digits in the hash
    import re
    if not re.match('^[0-9a-fA-F]+$', hash):
      return False
    return True
